#!/bin/bash

# Script to import groups into Terraform state
# This imports existing Cribl groups that were generated by generate-groups.go

set -e

echo "🚀 Importing groups into Terraform state..."
echo ""

# Initialize Terraform if not already done
if [ ! -d ".terraform" ]; then
    echo "📦 Initializing Terraform..."
    terraform init
    echo ""
fi

# Import groups based on the generated groups.tf file
# The import ID format for criblio_group is: <product>:<group_id>
# But we need to check - might just be <group_id>

echo "📥 Importing groups..."

# Extract resource names and IDs from groups.tf
# This parses the groups.tf file to get resource names and IDs

while IFS= read -r line; do
    # Match resource "criblio_group" "resource_name"
    if [[ $line =~ resource\ \"criblio_group\"\ \"([^\"]+)\" ]]; then
        resource_name="${BASH_REMATCH[1]}"
        # Read next few lines to get id and product
        id=""
        product=""
        read_count=0
        while IFS= read -r next_line && [ $read_count -lt 5 ]; do
            if [[ $next_line =~ id\ =\ \"([^\"]+)\" ]]; then
                id="${BASH_REMATCH[1]}"
            fi
            if [[ $next_line =~ product\ =\ \"([^\"]+)\" ]]; then
                product="${BASH_REMATCH[1]}"
            fi
            if [ -n "$id" ] && [ -n "$product" ]; then
                break
            fi
            read_count=$((read_count + 1))
        done
        if [ -n "$id" ] && [ -n "$product" ]; then
            import_id="${product}:${id}"
            echo "  Importing: criblio_group.${resource_name} (${import_id})"
            terraform import "criblio_group.${resource_name}" "${import_id}" || echo "    ⚠️  Failed to import (may already be in state)"
        fi
    fi
done < groups.tf

echo ""
echo "✅ Import complete!"
echo ""
echo "💡 Next steps:"
echo "   1. Review the state: terraform show"
echo "   2. Check for drift: terraform plan"
echo "   3. Apply any changes: terraform apply"
echo ""

